#include "SYsULexer.h"
#include <fstream>
#include <iostream>
#include <unordered_map>
#include <sstream>
#include <vector>

std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Int", "int" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "RightBrace", "r_brace" },
  { "LeftBrace", "l_brace" },
